function toSlug(name: string) {
  return name.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "")
}

export async function POST(req: NextRequest) {
  try {
    const body = await req.json()
    const { password, mode } = body

    if (!password || password !== ADMIN_PASSWORD) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
    }

    // mode=update patches existing records with description, twitter, and logo
    if (mode === "update") {
      let updated = 0
      for (const p of ARC_PROJECTS) {
        await pool.query(
          `UPDATE projects
           SET description = $1, twitter = $2, logo_url = $3
           WHERE LOWER(name) = LOWER($4) AND badge = 'official'`,
          [p.description || null, p.twitter || null, `https://icon.horse/icon/${p.logo}`, p.name]
        )
        updated++
      }
      return NextResponse.json({ success: true, updated, total: ARC_PROJECTS.length })
    }

    // default mode: insert new records
    const [existingNamesRes, existingSlugsRes] = await Promise.all([
      pool.query(`SELECT LOWER(name) AS name FROM projects`),
      pool.query(`SELECT slug FROM projects`),
    ])
    const existingNames = new Set(existingNamesRes.rows.map((r: any) => r.name as string))
    const existingSlugs = new Set(existingSlugsRes.rows.map((r: any) => r.slug as string))

    const toInsert: { name: string; tagline: string; description: string; category: string; logo_url: string; website: string; slug: string; twitter: string | null }[] = []
    let skipped = 0

    for (const p of ARC_PROJECTS) {
      if (existingNames.has(p.name.toLowerCase())) { skipped++; continue }

      let slug = toSlug(p.name)
      const base = slug
      let i = 1
      while (existingSlugs.has(slug)) slug = `${base}-${++i}`
      existingSlugs.add(slug)

      toInsert.push({
        name:        p.name,
        tagline:     p.tagline,
        description: p.description || "",
        category:    p.category,
        logo_url:    `https://logo.clearbit.com/${p.logo}`,
        website:     p.website,
        slug,
        twitter:     p.twitter || null,
      })
    }

    if (toInsert.length > 0) {
      const placeholders = toInsert.map((_, i) => {
        const b = i * 8
        return `($${b+1},$${b+2},$${b+3},$${b+4},$${b+5},$${b+6},$${b+7},$${b+8},'official',true,true,false)`
      }).join(",")

      const params = toInsert.flatMap(p => [p.name, p.tagline, p.description, p.category, p.logo_url, p.website, p.slug, p.twitter])

      await pool.query(
        `INSERT INTO projects (name, tagline, description, category, logo_url, website, slug, twitter, badge, approved, live, featured)
         VALUES ${placeholders}`,
        params
      )
    }

    return NextResponse.json({
      success:  true,
      inserted: toInsert.length,
      skipped,
      total:    ARC_PROJECTS.length,
    })
  } catch (err) {
    console.error("[SeedArc]", err)
    return NextResponse.json({ error: String(err) }, { status: 500 })
  }
}
